  ('aboriginal-f0899a01-moex-00049', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公物之敘述，下列何者正確？', '["公物係直接或間接供公目的使用之物", "公物實際上皆須提供公用", "公物限於民法上所稱之物", "公物皆須受公權力支配"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00050', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於法規命令及行政規則之敘述，下列何者正確？', '["法規命令訂定前原則上應將草案公告，行政規則無須踐行此程序", "行政規則應有法律之明確授權，始得訂定之", "法規命令係以下級機關或屬官為規範對象", "法規命令須函送立法院，經立法院核可後，始生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00051', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於法規命令之合法要件，下列敘述何者錯誤？', '["法規命令依法應經其他機關核准，而未經核准者無效", "法規命令牴觸法律或憲法者，無效", "法律授權主管機關訂定法規命令者，不得以行政規則替代之", "行政機關於制定法規命令後，未依法移送立法院備查者無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00052', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公法上請求權之敘述，下列何者錯誤？', '["於請求權人為行政機關時，除法律另有規定外，因5年間不行使而消滅", "於請求權人為人民時，除法律另有規定外，因10年間不行使而消滅", "公法上請求權因時效完成而消滅者，義務人取得抗辯權", "國家賠償請求權，自請求權人知有損害時起，因2年間不行使而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00053', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政處分之分類，下列敘述何者正確？', '["形成處分係直接設定、變更或消滅具體法律關係，僅能形成公法上法律關係", "確認處分係確定特定法律關係，但確認後，仍須處分相對人履行公法上行為義務，始生確認效力", "下命處分係課以相對人特定作為、不作為或忍受義務；處分相對人未履行義務時，行政機關得以該 處分為執行名義強制執行", "許可處分係形成處分之子類型，因須事前審查人民擬從事行為之合法性，常有違憲之虞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00054', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者非屬合法授益處分得依職權廢止之事由？', '["原處分機關保留行政處分之廢止權者", "附負擔之行政處分，受益人已履行該負擔者", "行政處分所依據之法規或事實事後發生變更，致不廢止該處分對公益將有危害者", "為防止或除去對公益之重大危害者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00055', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政處分轉換要件之敘述，下列何者錯誤？', '["原處分係違法處分，且無不得依職權撤銷之情形", "原處分與轉換後處分之目的得不相同", "原處分轉換後不得使當事人承受更不利之法律效果", "原處分是羈束處分，轉換後仍應維持為羈束處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
